#include <iostream>
#include <string>
#include <iomanip>

class BankAccount {
private:
    double balance;
public:
    BankAccount(double initialBalance = 0.0) : balance(initialBalance) {}
    void deposit(double amount) {
        balance += amount;
    }
    void withdraw(double amount) {
        balance -= amount;
    }
    double getBalance() const {
        return balance;
    }
};

int main() {
    std::cout << std::fixed << std::setprecision(2);
    BankAccount account(100.0);
    std::cout << "Initial balance: " << account.getBalance() << std::endl;
    std::cout << "Attempting deposit of -50.00..." << std::endl;
    account.deposit(-50.0);
    std::cout << "Balance after negative deposit: " << account.getBalance() << std::endl;
    std::cout << "Attempting withdraw of 100.00..." << std::endl;
    account.withdraw(100.0);
    std::cout << "Balance after over-withdrawal: " << account.getBalance() << std::endl;
    std::cout << "Attempting withdraw of -20.00..." << std::endl;
    account.withdraw(-20.0);
    std::cout << "Balance after negative withdrawal: " << account.getBalance() << std::endl;
    std::cout << "Final balance: " << account.getBalance() << std::endl;
    return 0;
}
